1	import { createHash, randomUUID } from "node:crypto";
2	import { existsSync, readFileSync, statSync } from "node:fs";
3	import path from "node:path";
4	import type { ClaudeAdapter, ClaudeJsonResponse } from "./claude.js";
5	import type { ClusterToolProfile, RouterDatabase } from "./db.js";
6	import { profilePromptOptions, type VerifierToolProfile } from "./profiles.js";
7	
8	export interface FactsheetEvidence {
9	  path: string;
10	  hash?: string;
11	  selector?: string;
12	}
13	
14	export interface FactsheetFact {
15	  id: string;
16	  claim: string;
17	  confidence?: string;
18	  evidence: FactsheetEvidence[];
19	}
20	
21	export interface FactsheetInput {
22	  schema_version?: number;
23	  cluster_id?: string;
24	  summary?: string;
25	  facts?: FactsheetFact[];
26	  pitfalls?: Array<{ id?: string; text?: string }>;
27	  forbidden_inferences?: string[];
28	}
