30	export interface VerifiedFactsheet {
31	  schema_version: 1;
32	  cluster_id: string;
33	  summary: string;
34	  facts: Array<{
35	    id: string;
36	    claim: string;
37	    confidence: "static_verified" | "llm_verified";
38	    evidence: Array<{
39	      path: string;
40	      hash: string;
41	      selector?: string;
42	    }>;
43	  }>;
44	  pitfalls: Array<{ id: string; text: string }>;
45	  forbidden_inferences: string[];
46	  omitted_facts: number;
47	}
48	
49	export interface RejectedFact {
50	  id: string;
51	  claim: string;
52	  reason: string;
53	}
54	
55	export interface StaticFactsheetVerification {
56	  factsheet: VerifiedFactsheet;
57	  fileHashes: Array<{
58	    path: string;
59	    hash: string;
60	    fileSize: number;
61	  }>;
62	  rejectedFacts: RejectedFact[];
63	}
64	
65	export interface PrepareClusterInput {
66	  projectId: string;
67	  clusterId: string;
68	  name?: string;
69	  description?: string;
70	  toolProfileDefault: ClusterToolProfile;
71	  factsheet: FactsheetInput;
72	  sourceSessionId?: string | null;
73	  gitRev?: string | null;
74	  verificationMode?: "static" | "llm";
75	  llmVerifierProfile?: VerifierToolProfile;
76	}
77	
78	export interface PrepareClusterResult {
79	  cluster_id: string;
80	  factsheet_id: string;
81	  factsheet_version: number;
82	  verification_stage: "static" | "llm";
83	  trust_state: "static_verified" | "partial_static" | "llm_verified" | "partial_llm";
84	  verified_facts: number;
85	  rejected_facts: number;
86	  rejected_fact_details: RejectedFact[];
87	  factsheet: VerifiedFactsheet;
88	  verifier_metrics?: {
89	    tool_profile: VerifierToolProfile;
90	    duration_ms: number;
91	    tokens_in?: number;
92	    tokens_out?: number;
93	  };
94	}
95	
96	export interface LlmVerifierFactResult {
97	  id: string;
98	  verdict: "VERIFIED" | "UNVERIFIED" | "AMBIGUOUS";
99	  reason: string;
100	}
101	
102	export interface LlmFactsheetVerification {
103	  factsheet: VerifiedFactsheet;
104	  rejectedFacts: RejectedFact[];
105	  verifierResults: LlmVerifierFactResult[];
106	  response: ClaudeJsonResponse;
107	  durationMs: number;
108	  toolProfile: VerifierToolProfile;
109	}
110	
111	interface VerifiedEvidenceFile {
112	  path: string;
113	  hash: string;
114	  fileSize: number;
115	  content: string;
116	}
117	
118	export function prepareStaticCluster(
119	  db: RouterDatabase,
120	  cwd: string,
121	  input: PrepareClusterInput
122	): PrepareClusterResult {
123	  const cluster = db.upsertCluster({
124	    id: input.clusterId,
125	    projectId: input.projectId,
126	    name: input.name ?? input.clusterId,
127	    description: input.description,
128	    toolProfileDefault: input.toolProfileDefault
129	  });
130	  const verification = verifyFactsheetStatic(cwd, input.clusterId, input.factsheet);
131	  ensureHasVerifiedFacts(db, input.projectId, input.clusterId, verification);
132	
133	  const trustState = verification.rejectedFacts.length === 0 ? "static_verified" : "partial_static";
134	  const factsheetRecord = db.insertClusterFactsheet({
135	    id: `factsheet_${randomUUID()}`,
136	    clusterId: cluster.id,
137	    contentJson: JSON.stringify(verification.factsheet),
138	    sourceSessionId: input.sourceSessionId,
139	    gitRev: input.gitRev,
140	    status: "static_verified",
141	    trustState,
142	    fileHashes: verification.fileHashes
143	  });
144	
145	  return {
146	    cluster_id: cluster.id,
147	    factsheet_id: factsheetRecord.id,
148	    factsheet_version: factsheetRecord.version,
149	    verification_stage: "static",
150	    trust_state: trustState,
151	    verified_facts: verification.factsheet.facts.length,
152	    rejected_facts: verification.rejectedFacts.length,
153	    rejected_fact_details: verification.rejectedFacts,
154	    factsheet: verification.factsheet
155	  };
156	}
157	
158	export async function prepareCluster(
159	  db: RouterDatabase,
160	  cwd: string,
161	  claude: ClaudeAdapter,
162	  input: PrepareClusterInput
163	): Promise<PrepareClusterResult> {
164	  const cluster = db.upsertCluster({
165	    id: input.clusterId,
166	    projectId: input.projectId,
167	    name: input.name ?? input.clusterId,
168	    description: input.description,
169	    toolProfileDefault: input.toolProfileDefault
170	  });
171	
172	  const verification = verifyFactsheetStatic(cwd, input.clusterId, input.factsheet);
173	  ensureHasVerifiedFacts(db, input.projectId, input.clusterId, verification);
174	
175	  if ((input.verificationMode ?? "static") !== "llm") {
176	    const trustState = verification.rejectedFacts.length === 0 ? "static_verified" : "partial_static";
177	    const factsheetRecord = db.insertClusterFactsheet({
178	      id: `factsheet_${randomUUID()}`,
179	      clusterId: cluster.id,
180	      contentJson: JSON.stringify(verification.factsheet),
181	      sourceSessionId: input.sourceSessionId,
182	      gitRev: input.gitRev,
183	      status: "static_verified",
184	      trustState,
185	      fileHashes: verification.fileHashes
186	    });
187	
188	    return {
189	      cluster_id: cluster.id,
190	      factsheet_id: factsheetRecord.id,
191	      factsheet_version: factsheetRecord.version,
192	      verification_stage: "static",
193	      trust_state: trustState,
194	      verified_facts: verification.factsheet.facts.length,
195	      rejected_facts: verification.rejectedFacts.length,
196	      rejected_fact_details: verification.rejectedFacts,
197	      factsheet: verification.factsheet
198	    };
199	  }
200	
201	  const llmVerification = await verifyFactsheetWithLlm(
202	    claude,
203	    cwd,
204	    verification.factsheet,
205	    input.llmVerifierProfile ?? "focused"
206	  );
207	  if (llmVerification.factsheet.facts.length === 0) {
208	    db.logClusterEvent({
209	      clusterId: input.clusterId,
210	      projectId: input.projectId,
211	      eventType: "factsheet_rejected",
212	      details: {
213	        static_rejected_facts: verification.rejectedFacts,
214	        llm_rejected_facts: llmVerification.rejectedFacts
215	      }
216	    });
217	    throw new Error("factsheet has no LLM verified facts");
218	  }
219	
220	  const rejectedFacts = [...verification.rejectedFacts, ...llmVerification.rejectedFacts];
221	  llmVerification.factsheet.omitted_facts = rejectedFacts.length;
222	  const trustState = rejectedFacts.length === 0 ? "llm_verified" : "partial_llm";
223	  const factsheetRecord = db.insertClusterFactsheet({
224	    id: `factsheet_${randomUUID()}`,
225	    clusterId: cluster.id,
226	    contentJson: JSON.stringify(llmVerification.factsheet),
227	    sourceSessionId: input.sourceSessionId,
228	    gitRev: input.gitRev,
229	    status: "llm_verified",
230	    trustState,
231	    fileHashes: fileHashesForFacts(verification.fileHashes, llmVerification.factsheet)
232	  });
233	  db.logClusterEvent({
234	    clusterId: cluster.id,
235	    projectId: input.projectId,
236	    eventType: "llm_verifier",
237	    details: {
238	      tool_profile: llmVerification.toolProfile,
239	      factsheet_id: factsheetRecord.id,
240	      factsheet_version: factsheetRecord.version,
241	      verifier_results: llmVerification.verifierResults
242	    },
243	    durationMs: llmVerification.durationMs,
244	    tokensIn: llmVerification.response.tokensIn,
245	    tokensOut: llmVerification.response.tokensOut
246	  });
247	
248	  return {
249	    cluster_id: cluster.id,
250	    factsheet_id: factsheetRecord.id,
251	    factsheet_version: factsheetRecord.version,
252	    verification_stage: "llm",
253	    trust_state: trustState,
254	    verified_facts: llmVerification.factsheet.facts.length,
255	    rejected_facts: rejectedFacts.length,
256	    rejected_fact_details: rejectedFacts,
257	    factsheet: llmVerification.factsheet,
258	    verifier_metrics: {
259	      tool_profile: llmVerification.toolProfile,
260	      duration_ms: llmVerification.durationMs,
261	      tokens_in: llmVerification.response.tokensIn,
262	      tokens_out: llmVerification.response.tokensOut
263	    }
264	  };
265	}
266	
267	export function verifyFactsheetStatic(
268	  cwd: string,
269	  clusterId: string,
270	  factsheet: FactsheetInput
271	): StaticFactsheetVerification {
272	  if (factsheet.cluster_id && factsheet.cluster_id !== clusterId) {
273	    throw new Error(`factsheet cluster_id ${factsheet.cluster_id} does not match ${clusterId}`);
274	  }
275	
276	  const facts = Array.isArray(factsheet.facts) ? factsheet.facts : [];
277	  const verifiedFacts: VerifiedFactsheet["facts"] = [];
278	  const rejectedFacts: RejectedFact[] = [];
279	  const fileHashes = new Map<string, { path: string; hash: string; fileSize: number }>();
280	
281	  for (const fact of facts) {
282	    const factId = stringOrEmpty(fact.id);
283	    const claim = stringOrEmpty(fact.claim);
284	    const evidence = Array.isArray(fact.evidence) ? fact.evidence : [];
285	    if (!factId || !claim || evidence.length === 0) {
286	      rejectedFacts.push({
287	        id: factId || "missing-id",
288	        claim,
289	        reason: "fact requires id, claim, and at least one evidence entry"
290	      });
291	      continue;
292	    }
293	
294	    const verifiedEvidence: VerifiedFactsheet["facts"][number]["evidence"] = [];
295	    const rejectionReasons: string[] = [];
296	    for (const item of evidence) {
297	      try {
298	        const file = readVerifiedEvidenceFile(cwd, item.path);
299	        const selector = item.selector ? String(item.selector) : undefined;
300	        if (selector && !file.content.includes(selector)) {
301	          rejectionReasons.push(`selector not found in ${file.path}: ${selector}`);
302	          continue;
303	        }
304	        if (item.hash && item.hash !== file.hash && item.hash !== `sha256:${file.hash}`) {
305	          rejectionReasons.push(`hash mismatch for ${file.path}`);
306	          continue;
307	        }
308	        verifiedEvidence.push({
309	          path: file.path,
310	          hash: `sha256:${file.hash}`,
311	          ...(selector ? { selector } : {})
312	        });
313	        fileHashes.set(file.path, {
314	          path: file.path,
315	          hash: `sha256:${file.hash}`,
316	          fileSize: file.fileSize
317	        });
318	      } catch (error: unknown) {
319	        rejectionReasons.push(error instanceof Error ? error.message : String(error));
320	      }
321	    }
322	
323	    if (verifiedEvidence.length !== evidence.length) {
324	      rejectedFacts.push({
325	        id: factId,
326	        claim,
327	        reason: rejectionReasons.join("; ") || "not all evidence entries verified"
328	      });
329	      continue;
330	    }
331	
332	    verifiedFacts.push({
333	      id: factId,
334	      claim,
335	      confidence: "static_verified",
336	      evidence: verifiedEvidence
337	    });
338	  }
339	
340	  return {
341	    factsheet: {
342	      schema_version: 1,
343	      cluster_id: clusterId,
344	      summary: stringOrEmpty(factsheet.summary).slice(0, 500),
345	      facts: verifiedFacts,
346	      pitfalls: sanitizePitfalls(factsheet.pitfalls),
347	      forbidden_inferences: sanitizeStringArray(factsheet.forbidden_inferences, 20, 300),
348	      omitted_facts: rejectedFacts.length
349	    },
350	    fileHashes: [...fileHashes.values()],
351	    rejectedFacts
352	  };
353	}
354	
355	export async function verifyFactsheetWithLlm(
356	  claude: ClaudeAdapter,
357	  cwd: string,
358	  factsheet: VerifiedFactsheet,
359	  toolProfile: VerifierToolProfile
360	): Promise<LlmFactsheetVerification> {
361	  const prompt = buildLlmVerifierPrompt(cwd, factsheet);
362	  const start = Date.now();
363	  const response =
364	    claude.runPromptWithOptions !== undefined
365	      ? await claude.runPromptWithOptions(prompt, profilePromptOptions(toolProfile))
366	      : await claude.runPrompt(prompt);
367	  const durationMs = Date.now() - start;
368	  const verifierResults = parseLlmVerifierResponse(response.result);
369	  const resultById = new Map(verifierResults.map((result) => [result.id, result]));
370	  const promotedFacts: VerifiedFactsheet["facts"] = [];
371	  const rejectedFacts: RejectedFact[] = [];
372	
373	  for (const fact of factsheet.facts) {
374	    const verdict = resultById.get(fact.id);
375	    if (verdict?.verdict === "VERIFIED") {
376	      promotedFacts.push({
377	        ...fact,
378	        confidence: "llm_verified"
379	      });
380	      continue;
381	    }
382	    rejectedFacts.push({
383	      id: fact.id,
384	      claim: fact.claim,
385	      reason: `llm_verifier:${verdict?.verdict ?? "MISSING"} ${verdict?.reason ?? "verifier did not return this fact"}`
386	    });
387	  }
388	
389	  return {
390	    factsheet: {
391	      ...factsheet,
392	      facts: promotedFacts,
393	      omitted_facts: factsheet.omitted_facts + rejectedFacts.length
394	    },
395	    rejectedFacts,
396	    verifierResults,
397	    response,
398	    durationMs,
399	    toolProfile
400	  };
401	}
402	
403	export function parseLlmVerifierResponse(source: string): LlmVerifierFactResult[] {
404	  const json = extractJsonObject(source);
405	  const parsed: unknown = JSON.parse(json);
406	  if (!isObject(parsed) || !Array.isArray(parsed.facts)) {
407	    throw new Error("LLM verifier response must be a JSON object with a facts array");
408	  }
409	
410	  const results: LlmVerifierFactResult[] = [];
411	  for (const item of parsed.facts) {
412	    if (!isObject(item)) {
413	      continue;
414	    }
415	    const id = stringOrEmpty(item.id);
416	    const verdict = stringOrEmpty(item.verdict).toUpperCase();
417	    if (!id || (verdict !== "VERIFIED" && verdict !== "UNVERIFIED" && verdict !== "AMBIGUOUS")) {
418	      continue;
419	    }
420	    results.push({
421	      id,
422	      verdict,
423	      reason: stringOrEmpty(item.reason).slice(0, 500)
424	    });
425	  }
426	
427	  if (results.length === 0) {
428	    throw new Error("LLM verifier response did not contain usable fact verdicts");
429	  }
430	  return results;
431	}
432	
433	function readVerifiedEvidenceFile(cwd: string, inputPath: string): VerifiedEvidenceFile {
434	  const relativePath = normalizeEvidencePath(inputPath);
435	  const absoluteCwd = path.resolve(cwd);
436	  const absolutePath = path.resolve(absoluteCwd, relativePath);
437	  if (absolutePath !== absoluteCwd && !absolutePath.startsWith(`${absoluteCwd}${path.sep}`)) {
438	    throw new Error(`evidence path escapes project cwd: ${inputPath}`);
439	  }
440	  if (!existsSync(absolutePath)) {
441	    throw new Error(`evidence path does not exist: ${relativePath}`);
442	  }
443	  const stat = statSync(absolutePath);
444	  if (!stat.isFile()) {
445	    throw new Error(`evidence path is not a file: ${relativePath}`);
446	  }
447	  const content = readFileSync(absolutePath, "utf8");
448	  return {
449	    path: relativePath,
450	    hash: createHash("sha256").update(content).digest("hex"),
451	    fileSize: stat.size,
452	    content
453	  };
454	}
455	
456	function ensureHasVerifiedFacts(
457	  db: RouterDatabase,
458	  projectId: string,
459	  clusterId: string,
460	  verification: StaticFactsheetVerification
461	): void {
462	  if (verification.factsheet.facts.length > 0) {
463	    return;
464	  }
465	  db.logClusterEvent({
466	    clusterId,
467	    projectId,
468	    eventType: "factsheet_rejected",
469	    details: {
470	      rejected_facts: verification.rejectedFacts
471	    }
472	  });
473	  throw new Error("factsheet has no statically verified facts");
474	}
475	
476	function fileHashesForFacts(
477	  staticFileHashes: StaticFactsheetVerification["fileHashes"],
478	  factsheet: VerifiedFactsheet
479	): StaticFactsheetVerification["fileHashes"] {
480	  const usedPaths = new Set(factsheet.facts.flatMap((fact) => fact.evidence.map((evidence) => evidence.path)));
481	  return staticFileHashes.filter((file) => usedPaths.has(file.path));
482	}
483	
484	function buildLlmVerifierPrompt(cwd: string, factsheet: VerifiedFactsheet): string {
485	  const facts = factsheet.facts.map((fact) => ({
486	    id: fact.id,
487	    claim: fact.claim,
488	    evidence: fact.evidence.map((evidence) => {
489	      const file = readVerifiedEvidenceFile(cwd, evidence.path);
490	      return {
491	        path: evidence.path,
492	        selector: evidence.selector ?? null,
493	        snippet: snippetForEvidence(file.content, evidence.selector)
494	      };
495	    })
496	  }));
497	
498	  return [
499	    "You are verifying a cluster factsheet for AgentSessionRouter.",
500	    "For each fact, decide whether the supplied evidence semantically supports the claim.",
501	    "Return VERIFIED only when the claim follows from the evidence.",
502	    "Return UNVERIFIED when support is missing or the claim names APIs/config that are not shown.",
503	    "Return AMBIGUOUS when the evidence is related but insufficient.",
504	    "Do not infer. Do not use tools. Return JSON only.",
505	    "",
506	    "Expected JSON shape:",
507	    '{"facts":[{"id":"fact-id","verdict":"VERIFIED|UNVERIFIED|AMBIGUOUS","reason":"short reason"}]}',
508	    "",
509	    `Factsheet cluster_id: ${factsheet.cluster_id}`,
510	    `Facts to verify: ${JSON.stringify(facts, null, 2)}`
511	  ].join("\n");
512	}
513	
514	function snippetForEvidence(content: string, selector: string | undefined): string {
515	  const maxLength = 1600;
516	  if (!selector) {
517	    return content.slice(0, maxLength);
518	  }
519	  const index = content.indexOf(selector);
520	  if (index < 0) {
521	    return content.slice(0, maxLength);
522	  }
523	  const start = Math.max(0, index - 500);
524	  const end = Math.min(content.length, index + selector.length + 900);
525	  return content.slice(start, end);
526	}
527	
528	function extractJsonObject(source: string): string {
529	  const trimmed = source.trim();
530	  const fenced = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/i);
531	  const candidate = fenced?.[1]?.trim() ?? trimmed;
532	  const start = candidate.indexOf("{");
533	  const end = candidate.lastIndexOf("}");
534	  if (start < 0 || end < start) {
535	    throw new Error("LLM verifier response did not include a JSON object");
536	  }
537	  return candidate.slice(start, end + 1);
538	}
539	
540	function normalizeEvidencePath(inputPath: string): string {
541	  if (!inputPath || path.isAbsolute(inputPath)) {
542	    throw new Error(`evidence path must be relative: ${inputPath}`);
543	  }
544	  const normalized = path.normalize(inputPath).replaceAll("\\", "/");
545	  if (normalized === "." || normalized.startsWith("../") || normalized === "..") {
546	    throw new Error(`evidence path escapes project cwd: ${inputPath}`);
547	  }
548	  return normalized;
549	}
550	
551	function sanitizePitfalls(value: unknown): Array<{ id: string; text: string }> {
552	  if (!Array.isArray(value)) {
553	    return [];
554	  }
555	  const result: Array<{ id: string; text: string }> = [];
556	  for (const item of value) {
557	    if (!isObject(item)) {
558	      continue;
559	    }
560	    const id = stringOrEmpty(item.id).slice(0, 120);
561	    const text = stringOrEmpty(item.text).slice(0, 500);
562	    if (!id || !text) {
563	      continue;
564	    }
565	    result.push({ id, text });
566	    if (result.length >= 20) {
567	      break;
568	    }
569	  }
570	  return result;
571	}
572	
573	function sanitizeStringArray(value: unknown, maxItems: number, maxLength: number): string[] {
574	  if (!Array.isArray(value)) {
575	    return [];
576	  }
577	  return value
578	    .map((item) => String(item).trim())
579	    .filter(Boolean)
580	    .slice(0, maxItems)
581	    .map((item) => item.slice(0, maxLength));
582	}
583	
584	function stringOrEmpty(value: unknown): string {
585	  return typeof value === "string" ? value.trim() : "";
586	}
587	
588	function isObject(value: unknown): value is Record<string, unknown> {
589	  return typeof value === "object" && value !== null && !Array.isArray(value);
590	}
