825	function isVerifiedFactsheetStatus(status: ClusterFactsheetStatus): boolean {
826	  return status === "static_verified" || status === "llm_verified";
827	}
828	
829	function factsheetEventType(status: ClusterFactsheetStatus, trustState: ClusterTrustState | undefined): string {
830	  if (trustState === "partial_static") {
831	    return "factsheet_partially_static_verified";
832	  }
833	  if (trustState === "partial_llm") {
834	    return "factsheet_partially_llm_verified";
835	  }
836	  if (status === "static_verified") {
837	    return "factsheet_static_verified";
838	  }
839	  if (status === "llm_verified") {
840	    return "factsheet_llm_verified";
841	  }
842	  return status === "rejected" ? "factsheet_rejected" : "factsheet_generated";
843	}
